const section = document.querySelector('#periodo-revolucion');

// AC1: Minimum 12 events with detailed content
const eventCards = section.querySelectorAll('.event-card');
const ac1 = eventCards.length >= 12;

// AC2: Each event has text + multimedia (spot check first 5)
let imagesFound = 0;
let textLengthOk = 0;
const sampleCards = Array.from(eventCards).slice(0, 5);
sampleCards.forEach(card => {
  if (card.querySelector('img, figure, .card-image')) imagesFound++;
  const textContent = card.innerText || '';
  if (textContent.length > 150) textLengthOk++;
});

// AC3: Alberdi as thread conductor - count Alberdi-connected vs total
let alberdiCards = 0;
eventCards.forEach(card => {
  if ((card.innerText || '').toLowerCase().includes('alberdi')) alberdiCards++;
});

// AC5: Sub-navigation functional (4 links)
const subNavLinks = document.querySelectorAll('.sub-nav a');
const subNavFunctional = subNavLinks.length === 4;

// AC6: At least 2 interactive animations
const timeline = document.querySelector('.revolucion-timeline');
const toggles = document.querySelectorAll('.card-expand-toggle');
const ac6 = !!timeline && toggles.length >= 4;

// AC7: Hecho cards have cite elements
const hechoCards = section.querySelectorAll('[data-certeza="hecho"]');
let hechoWithCite = 0;
hechoCards.forEach(card => {
  if (card.querySelector('cite, footer, .card-source')) hechoWithCite++;
});

// AC8: All cards classified
let classifiedCards = 0;
eventCards.forEach(card => {
  if (card.getAttribute('data-certeza') || card.closest('[data-certeza]')) classifiedCards++;
});

// AC9: Opinion cards have attribution
const opinionCards = section.querySelectorAll('[data-certeza="opinion"]');
let opinionWithAttrib = 0;
opinionCards.forEach(card => {
  const text = card.innerText || '';
  if (card.querySelector('blockquote, .card-attribution, cite') || text.includes('—')) opinionWithAttrib++;
});

// AC10: Sources documented
const sourceEls = section.querySelectorAll('cite, .card-source, footer[class*="source"]');

({
  ac1_eventCount: eventCards.length,
  ac1_pass: ac1,
  ac2_imagesIn5: imagesFound,
  ac2_textOkIn5: textLengthOk,
  ac3_alberdiCards: alberdiCards,
  ac3_totalCards: eventCards.length,
  ac5_subNavLinks: subNavLinks.length,
  ac5_pass: subNavFunctional,
  ac6_timelineExists: !!timeline,
  ac6_toggleCount: toggles.length,
  ac6_pass: ac6,
  ac7_hechoCards: hechoCards.length,
  ac7_withCite: hechoWithCite,
  ac8_classifiedCards: classifiedCards,
  ac8_totalCards: eventCards.length,
  ac9_opinionCards: opinionCards.length,
  ac9_withAttrib: opinionWithAttrib,
  ac10_sourceElements: sourceEls.length
})

